    "level": 4,
    "school": "Evocação",
    "time": "1 ação",
    "range": "120 pés",
    "components": "V, S, M",
    "componentsDetail": "a small piece of phosphorus",
    "duration": "Concentração, até 1 minuto",
    "ritual": false,
